class Rules {
    int defaultCase;
    int noInlineComments;
    int operatorLinebreak;

    Rules({
        required this.defaultCase,
        required this.noInlineComments,
        required this.operatorLinebreak,
    });

    factory Rules.fromJson(Map<String, dynamic> json) => Rules(
        defaultCase: json["default-case"],
        noInlineComments: json["no-inline-comments"],
        operatorLinebreak: json["operator-linebreak"],
    );

    Map<String, dynamic> toJson() => {
        "default-case": defaultCase,
        "no-inline-comments": noInlineComments,
        "operator-linebreak": operatorLinebreak,
    };
}
